mapper.select:
SELECT p.id, p.product_name, p.category_id, pc.category_name, p.new_degree, p.price, p.original_price, p.product_desc, p.is_seckill, p.seckill_stock, p.pick_point_id, cpp.pick_point_name, p.product_status, p.user_id, u.username as publisher_name, u.credit_score as publisher_credit_score, p.create_time FROM t_product p LEFT JOIN t_product_category pc ON p.category_id = pc.id LEFT JOIN t_campus_pick_point cpp ON p.pick_point_id = cpp.id LEFT JOIN t_user u ON p.user_id = u.id
p.is_deleted = 0
AND (p.product_name LIKE CONCAT('%', #{keyword}, '%') OR p.product_desc LIKE CONCAT('%', #{keyword}, '%'))
AND p.category_id = #{categoryId}
AND p.price >= #{minPrice}
AND p.price <= #{maxPrice}
AND p.new_degree = #{newDegree}
AND p.is_seckill = #{isSeckill}
AND p.product_status = #{productStatus}
AND p.user_id = #{userId}
ORDER BY p.price ${sortOrder}
ORDER BY p.create_time ${sortOrder}
ORDER BY p.create_time DESC
